// Projection: linear mercator over the WA/OR/CA bbox we sampled.
const MIN_LON = -124.733174;
const MAX_LAT = 49.002357;
const MID_LAT = 40.76825650000001;
const SCALE = 24.53212709755;
const PAD = 8;

const RAD = Math.PI / 180;
const COS_MID = Math.cos(MID_LAT * RAD);

export function projectLatLng(lat: number, lng: number): { x: number; y: number } {
  const x = PAD + (lng - MIN_LON) * COS_MID * SCALE;
  const y = PAD + (MAX_LAT - lat) * SCALE;
  return { x, y };
}
